-- V11: terms_versions 테이블에 약관 본문(content) 컬럼 추가 및 초기 데이터 적재

ALTER TABLE terms_versions ADD COLUMN content text;

-- ── SERVICE (이용약관) ──────────────────────────────────────────────────────
UPDATE terms_versions
SET content = '{"title":"이용약관","intro":"본 약관은 Newsift(이하 \"회사\")가 제공하는 AI 뉴스 큐레이션 서비스(이하 \"서비스\")의 이용과 관련하여 회사와 이용자의 권리·의무 및 책임사항을 규정합니다.","sections":[{"heading":"제1조 (목적)","paragraphs":["본 약관은 회사가 제공하는 서비스의 이용조건 및 절차, 회사와 회원 간의 권리·의무 및 책임사항을 규정함을 목적으로 합니다."]},{"heading":"제2조 (정의)","paragraphs":["\"서비스\"란 회사가 AI를 활용해 뉴스 기사를 수집·요약·분석하여 제공하는 일체의 서비스를 의미합니다.","\"회원\"이란 본 약관에 동의하고 계정을 생성하여 서비스를 이용하는 자를 말합니다.","\"콘텐츠\"란 서비스 내에서 제공되는 기사 요약, 편향 분석, 트렌드 등 일체의 정보를 의미합니다."]},{"heading":"제3조 (약관의 효력 및 변경)","paragraphs":["본 약관은 서비스 화면에 게시하거나 기타의 방법으로 회원에게 공지함으로써 효력이 발생합니다.","회사는 관련 법령을 위배하지 않는 범위에서 약관을 변경할 수 있으며, 변경 시 적용일자 및 사유를 명시하여 사전 공지합니다."]},{"heading":"제4조 (서비스의 제공 및 변경)","paragraphs":["회사는 연중무휴, 1일 24시간 서비스 제공을 원칙으로 합니다. 다만 시스템 점검 등의 사유로 일시 중단될 수 있습니다.","AI가 생성한 요약 및 분석 결과는 참고용이며, 회사는 그 정확성·완전성을 보증하지 않습니다."]},{"heading":"제5조 (회원의 의무)","paragraphs":["회원은 관계 법령, 본 약관의 규정, 이용안내 및 서비스상에 공지한 주의사항을 준수하여야 합니다.","회원은 서비스를 통해 얻은 정보를 회사의 사전 승낙 없이 영리 목적으로 이용하거나 제3자에게 제공할 수 없습니다."]},{"heading":"제6조 (책임의 제한)","paragraphs":["회사는 천재지변, 불가항력적 사유 또는 회원의 귀책사유로 발생한 서비스 이용 장애에 대해 책임을 지지 않습니다.","서비스에 게시된 뉴스 콘텐츠의 저작권은 원 저작권자에게 있으며, 회사는 큐레이션 및 분석 결과만을 제공합니다."]}]}'
WHERE type = 'SERVICE' AND is_active = TRUE;

-- ── PRIVACY (개인정보처리방침) ─────────────────────────────────────────────
UPDATE terms_versions
SET content = '{"title":"개인정보처리방침","intro":"Newsift(이하 \"회사\")는 이용자의 개인정보를 중요시하며, 「개인정보 보호법」 등 관련 법령을 준수합니다. 본 방침은 회사가 어떤 정보를 수집하고 어떻게 이용·보호하는지 안내합니다.","sections":[{"heading":"수집하는 개인정보 항목","paragraphs":["필수: 이메일 주소, 비밀번호(암호화 저장), 닉네임","소셜 로그인 시: 해당 서비스가 제공하는 프로필 식별자 및 이메일","자동 수집: 접속 IP, 기기·브라우저 정보, 서비스 이용 기록"]},{"heading":"개인정보의 수집 및 이용 목적","paragraphs":["회원 식별 및 가입 의사 확인, 서비스 제공 및 운영","맞춤형 뉴스 큐레이션 및 관심사 기반 추천","서비스 개선, 신규 기능 개발 및 통계 분석","공지사항 전달 및 고객 문의 응대"]},{"heading":"개인정보의 보유 및 이용 기간","paragraphs":["회원 탈퇴 시 지체 없이 파기함을 원칙으로 합니다.","관련 법령에 따라 보존 의무가 있는 경우 해당 기간 동안 보관합니다. (예: 전자상거래법에 따른 기록)"]},{"heading":"개인정보의 제3자 제공","paragraphs":["회사는 원칙적으로 이용자의 개인정보를 외부에 제공하지 않습니다.","다만 이용자가 사전 동의한 경우 또는 법령에 의해 요구되는 경우에 한해 제공할 수 있습니다."]},{"heading":"이용자의 권리와 행사 방법","paragraphs":["이용자는 언제든지 자신의 개인정보를 조회·수정하거나 처리 정지·삭제를 요청할 수 있습니다.","설정 메뉴 또는 고객센터를 통해 권리를 행사할 수 있습니다."]},{"heading":"개인정보 보호책임자","paragraphs":["성명: 개인정보보호팀","이용자는 서비스 이용 중 발생한 개인정보 관련 문의를 위 연락처로 신고할 수 있습니다."]}]}'
WHERE type = 'PRIVACY' AND is_active = TRUE;
